{
  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Jo iffatra Zeltt irr preeksch\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "To Besdeeewign guhstihs\nfawi Noseegumi/ un ar tawn\nGrehtu Saitehm taps wiach\ntaisihts.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Wiꞥſch nomirs tapehz/\nka wiꞥſch bes Pamahzifchanas\nbijts/ un eekſch fawas leelas Gef-\nkibas wiꞥſch nomaldifees.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ta VI. Llodalla.\nSalamans mahza/ ka ne buhs lehti Zittu Gal-\nwâ xemt: 1. Rahda to Slinki pee tahs\nSkudras/ lai no tahs mahzahs : 6. Aprahi\ntohs Aprunnatajus un wiltigu Mutti : 12\nPamahza us Paklanifchannu tohs Jannos :\n20. Mahza ka ne buhs Manzibu dſicht:\n24. Ro kuxras nahk ta Samaitafchana :\n22.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ans Behrns/ eſti tu\npreeksch tawu Tuwaku\ngalwojs/ un tarvu\nRohku pee kahdu Sweschu ap-\nkiblejis/\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Tad eſti tu fatihſtihts ar\nto Wallodu tawas Muttes/ un\nfawaldſinahts ar teem Wahr-\ndeem tawas Muttes.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Tad darri jelle ta mane\nBehrns/ un iſglahbees/ jo ti\neſti tawam Tuwakam Rohka\nnahzts/ eij/ padohdees pats/ un\npakubbina tawn Tuwaku.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ne leeſ tawahm Azzim\nnismigt/ nedg taweem Azzu-\nplakſtixeem ſnaust.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Iſglahbees ka Stirna ni\n(Meddineeka) Rohkas/ un ka\nPutnis no Putnineeka Rohkas.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Eij pee tahs Skudras tu\nSlinki/ luhto winnas Zettus/\nun tohpt gudrs.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Jepſchu tai ne kahds Leels-\nKungſ/ nei Wirtueeks nei Kungs\nirr.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "(Tomehr) ta fawu Maisi\nWaffara fataifa/ fawu Barribu\nfakrahj winxa ptaijamâ Laika.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Zik ilgi gulli tu Slinki?\nkad zeltees tu no tawa Meega?\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Gulli makkeniht/ fnaudi\nmakkeniht/ taleez Rohkas mak-\nkeniht/ ka tu gulli.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Tad usees tew tawa\nNabbadsiba ka Zetta-Wihrs/ un\ntas Truhkums ka apbrunnohts\nWihrs.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Weens Negohda Wihrs/\nweens weltigs Wihrs staiga ar\npahrwehrtitu Mutti.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Mirkschkina ar fawahin\nAzzim */ aiskustina ar fawahin\nRahjahm/ rahda ar faween Pirk-\nſteem.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "* Eebr: Wall Runna ar fawahin Kahjahm-\nPahrwehrtitas Leetas irr\nwinna Sirdi/ wiꞥſch dohdahs\nveennumebr us Pauna/ un zelt\nBahrchanas.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tapehz nahks winna No-\nnaitaſchana peepeschi/ ahtri taps\nwiꞥſch ſadansihts/ un Dseedi-\nnafchanas ne buhs.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Schibs fetchas Leetas ee-\nnihd tas KUNGS/ un to fepti-\ntu turr wiꞥſch par negantu.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Lepnas Azzis/ wiltigu\nMehli/ un Rohkas/ kas nenofee-\ngutchu Affini tsleij.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
